package settings

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/settings"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type SettingsProxy struct {
	settings.UnimplementedSettingsServer
	client settings.SettingsClient
}

func init() {
	proxyutil.Register(&settings.Settings_ServiceDesc, NewSettingsProxy)
}
func NewSettingsProxy(cc grpc.ClientConnInterface) settings.SettingsServer {
	return &SettingsProxy{client: settings.NewSettingsClient(cc)}
}
func (p *SettingsProxy) GetSettings(ctx context.Context, in *settings.SettingsRequest) (*settings.SettingsResponse, error) {
	return proxyutil.ProxyMethod[settings.SettingsRequest, settings.SettingsResponse](p.client.GetSettings)(ctx, in)
}
